params.script:
var classification = String($ivr.getObject("context.classification") || "");
var phonetype = String($ivr.getObject("context.phonetype") || "");
var result = "デフォルト";
if (classification === "キャンセル") {
    result = "キャンセル";
} else if (classification === "新規") {
    result = "新規";
} else if ((classification === "予約" || classification === "変更" || classification === "確認") && phonetype === "携帯") {
    result = "携帯";
} else if (classification === "予約" || classification === "変更" || classification === "確認") {
    result = "固定";
}
$runner.setResult(result);
